        "autocomplete_valid": "A form field has an invalid autocomplete value. Some assistive tech relies on these to fill in fields automatically.",
        "role_img_alt": "An element with role=\"img\" has no accessible name. Screen reader users will hear nothing.",
        "svg_img_alt": "An SVG used as an image has no accessible name."
